create table dirkspzm32.s_sap_idoc_outbound (
    docnum          varchar2(16 char) not null enable,
    segnum          varchar2(6 char) not null enable,
    psgnum          varchar2(6 char) not null enable,
    mandt           varchar2(3 char) not null enable,
    segnam          varchar2(30 char) not null enable,
    hlevel          varchar2(2 char) not null enable,
    sdata           varchar2(1000 char) not null enable,
    nachricht_idoc  number default 0 not null enable,
    nachricht_typ   varchar2(30 char) default 'BANK_CREATE' not null enable,
    nachricht_datum date default sysdate not null enable,
    transfer_status varchar2(3 char) default 'N' not null enable,
    fehler_code     number default 0 not null enable,
    fehler_text     varchar2(255 char),
    erstell_datum   date default sysdate not null enable,
    bearb_datum     date,
    export_datum    date,
    idoc_typ        varchar2(30 char) default 'BANK_CREATE01' not null enable
);

alter table dirkspzm32.s_sap_idoc_outbound
    add constraint pk_s_sap_idoc_outbound primary key ( docnum,
                                                        segnum )
        using index enable;


